import React, { useState } from 'react';
import './staff.css';

const Staff = () => {
    const [staffList, setStaffList] = useState([
        { id: "ST-101", name: "Emma Thompson", role: "Nurse", dept: "Emergency", shift: "Day", phone: "555-0123" },
        { id: "ST-102", name: "Liam Neeson", role: "Technician", dept: "Radiology", shift: "Night", phone: "555-0199" },
        { id: "ST-103", name: "Sophia Loren", role: "Receptionist", dept: "Front Desk", shift: "Day", phone: "555-0155" },
    ]);

    return (
        <div className="staff-page">
            <div className="staff-header">
                <div>
                    <h1>Staff Management</h1>
                    <p>Manage hospital employees, roles, and shifts.</p>
                </div>
                <button className="add-staff-btn">+ Add Staff Member</button>
            </div>

            <div className="staff-grid">
                {staffList.map((member) => (
                    <div className="staff-card" key={member.id}>
                        <div className="staff-avatar">{member.name.charAt(0)}</div>
                        <div className="staff-info">
                            <h3>{member.name}</h3>
                            <span className="staff-role">{member.role}</span>
                            <p><strong>Dept:</strong> {member.dept}</p>
                            <p><strong>Shift:</strong> {member.shift}</p>
                        </div>
                        <div className="staff-actions">
                            <button className="msg-btn">💬</button>
                            <button className="edit-btn">✏️</button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default Staff;
